import fs from 'node:fs';
import path from 'node:path';

const root = path.resolve(import.meta.dirname, '..');
const hub = fs.readFileSync(path.join(root, 'index.html'), 'utf8');
const cardPattern = /<div id="[^"]+" data-category="(?<category>[^"]+)" data-tool-slug="(?<slug>[^"]+)"[\s\S]*?<h3[^>]*>(?<title>[\s\S]*?)<\/h3>\s*<p[^>]*>(?<description>[\s\S]*?)<\/p>/g;
const strip = value => value.replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&#39;/g, "'").trim();
const tools = [...hub.matchAll(cardPattern)].map(match => ({
  category: match.groups.category,
  slug: match.groups.slug,
  title: strip(match.groups.title),
  description: strip(match.groups.description)
}));
const manualTools = [
  { category: 'converter', slug: 'color-converter', title: 'Color Converter', description: 'Convert HEX, RGB, RGBA, HSL, and Tailwind color formats.' },
  { category: 'game', slug: 'sprite-sheet-editor', title: 'Sprite Sheet Editor', description: 'Edit sprite grids, align frames, preview pixel animations, and export a corrected PNG.' }
];
for (const tool of manualTools) {
  if (!tools.some(item => item.slug === tool.slug)) tools.push(tool);
}
const doxxIndex = tools.findIndex(tool => tool.slug === 'doxx-click');
if (doxxIndex >= 0) tools.splice(doxxIndex, 1);

