function profile(tool) {
  if (specifics[tool.slug]) return specifics[tool.slug];
  if (unitFacts[tool.slug]) {
    const [subject, caution] = unitFacts[tool.slug];
    return [`This tool expresses the same ${subject} in different units by applying defined conversion relationships. Converting the unit changes the notation, not the underlying quantity.`, `Enter a known value, select the source and target units, and compare the result. Reversing the units is a useful quick check because it should return close to the starting value.`, caution];
  }
  if (operationDetails[tool.slug]) {
    const [example, caution] = operationDetails[tool.slug];
    return [`${tool.description} Its focused controls are intended to expose the settings that matter for this operation without requiring a full desktop editor or account.`, example, caution];
  }
  if (tool.category === 'image') return [`Digital images store a rectangular grid of pixels plus format-specific information. ${tool.description}`, 'Choose one local image, review the preview and settings, then download the result. Compare dimensions, transparency, sharpness, and file size before replacing an original.', 'Conversion cannot recreate detail already lost through compression or low resolution. JPEG does not preserve transparency, while PNG and WebP can; metadata may not survive browser re-encoding.'];
  if (tool.category === 'audio') return [`Digital audio represents sound as samples over time. Containers and codecs affect compatibility, quality, and file size. ${tool.description}`, 'Load one supported file, preview it when available, apply the operation, and listen to the downloaded result before using it in a project.', 'Re-encoding a lossy source cannot restore discarded detail. Long files consume more browser memory, and format support differs by browser and device.'];
  if (tool.category === 'video') return [`Digital video combines timed image frames, and often audio, inside a container. Codec, resolution, frame rate, and bitrate all influence compatibility and size. ${tool.description}`, 'Choose a supported local video, reveal the operation controls, select the needed range or output options, then process and inspect the downloaded file.', 'Browser processing can be memory intensive. Re-encoding may reduce quality, and a container extension alone does not guarantee that every device supports the codecs inside it.'];
  if (tool.category === 'generator') return [`${tool.title} combines curated word parts or browser-generated values to produce quick starting points. ${tool.description}`, 'Generate one result for immediate use, or use the count control and download option when you need a list to review away from the page.', 'Generated output is an idea, not a clearance check. Verify trademarks, existing usernames, cultural meaning, pronunciation, and project fit before publishing.'];
  if (tool.category === 'game') return [`${tool.title} is a lightweight browser activity built around randomized setup, timing, matching, or choice. ${tool.description}`, 'Read the visible controls, start a round, and use the result as entertainment, practice, or a neutral way to organize a casual activity.', 'Randomized results can vary from run to run. This tool is not designed for regulated gambling, prizes, clinical measurement, or high-stakes competition.'];
  return [`${tool.description} The result follows the values entered in the tool and updates without requiring an account.`, 'Enter realistic values, change one input at a time, and compare the result with a second calculation when the decision matters.', 'The output is an estimate and may omit fees, local rules, rounding policies, or circumstances outside the visible inputs.'];
}

function extraSources(tool) {
  const sources = [...(sourceSets[tool.category] || [])];
  if (tool.slug === 'stock-crypto-avg-cost-calculator') sources.unshift(['IRS Publication 550: Investment Income and Expenses', 'https://www.irs.gov/publications/p550']);
  if (['mortgage-calculator', 'loan-payment-calculator'].includes(tool.slug)) sources.unshift(['Consumer Financial Protection Bureau: Mortgages', 'https://www.consumerfinance.gov/consumer-tools/mortgages/']);
  if (tool.slug === 'compound-interest-calculator') sources.unshift(['Investor.gov Compound Interest Calculator', 'https://www.investor.gov/financial-tools-calculators/calculators/compound-interest-calculator']);
  if (tool.slug === 'bmi-calculator') sources.unshift(['CDC Adult BMI Categories', 'https://www.cdc.gov/bmi/adult-calculator/bmi-categories.html']);
  if (tool.slug === 'uuid-generator') sources.unshift(['RFC 9562: UUIDs', 'https://www.rfc-editor.org/rfc/rfc9562.html']);
  if (['image-to-base64', 'base64-to-image'].includes(tool.slug)) sources.unshift(['RFC 4648: Base Encodings', 'https://www.rfc-editor.org/rfc/rfc4648.html']);
  if (tool.slug === 'time-zone-converter') sources.unshift(['IANA Time Zone Database', 'https://www.iana.org/time-zones']);
  if (tool.slug === 'color-converter-picker') sources.unshift(['W3C CSS Color Module', 'https://www.w3.org/TR/css-color-4/']);
  if (tool.slug === 'subtitle-converter') sources.unshift(['W3C WebVTT', 'https://www.w3.org/TR/webvtt1/']);
  if (tool.slug === 'password-generator') sources.unshift(['OWASP Authentication Cheat Sheet', 'https://cheatsheetseries.owasp.org/cheatsheets/Authentication_Cheat_Sheet.html']);
  if (tool.slug === 'character-byte-counter') sources.unshift(['Unicode Core Specification', 'https://www.unicode.org/versions/Unicode16.0.0/core-spec/chapter-3/']);
  return sources.slice(0, 3);
}

const esc = value => value.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
