for (const tool of tools) {
  const dir = path.join(root, 'guides', guideSlug(tool));
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'index.html'), render(tool));
  const toolFile = path.join(root, tool.slug, 'index.html');
  if (!fs.existsSync(toolFile)) continue;
  let html = fs.readFileSync(toolFile, 'utf8');
  if (tool.slug === 'stock-crypto-avg-cost-calculator') {
    html = html.replace(/\s*<div class="mb-5 text-center"><a href="\/guides\/stock-crypto-avg-cost-calculator\/"[\s\S]*?<\/div>/, '');
    const stockFooterGuide = '<div class="mb-4 text-center"><a href="/guides/how-to-calculate-average-stock-cost/" class="tool-guide-link inline-flex items-center justify-center gap-2 rounded-xl border border-zinc-900 bg-zinc-900 px-5 py-2.5 text-sm font-bold text-white shadow-sm hover:border-zinc-700 hover:bg-zinc-700"><span aria-hidden="true">&#128214;</span>Guide</a></div>';
    if (!html.includes(stockFooterGuide)) {
      html = html.replace(/(<h2 class="mb-3 text-center text-sm font-black text-zinc-500">Stock\/Crypto Avg Cost Calculator<\/h2>)/, `$1\n                ${stockFooterGuide}`);
    }
  }
  if (!html.includes(`href="/guides/${guideSlug(tool)}/"`)) {
    const encodedTitle = esc(tool.title);
    const heading = new RegExp(`(<h2 class="mb-3 text-center text-sm font-black text-zinc-500">${encodedTitle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}<\\/h2>)`);
    html = html.replace(heading, `$1\n                <div class="mb-4 text-center"><a href="/guides/${guideSlug(tool)}/" class="tool-guide-link inline-flex items-center justify-center gap-2 rounded-xl border border-zinc-900 bg-zinc-900 px-5 py-2.5 text-sm font-bold text-white shadow-sm hover:border-zinc-700 hover:bg-zinc-700"><span aria-hidden="true">&#128214;</span>Guide</a></div>`);
  }
  fs.writeFileSync(toolFile, html);
}

const sitemapFile = path.join(root, 'sitemap.xml');
let sitemap = fs.readFileSync(sitemapFile, 'utf8');
const existingLocations = new Set([...sitemap.matchAll(/<loc>([^<]+)<\/loc>/g)].map(match => match[1]));
const guideEntries = tools
  .map(tool => `https://superfasttool.com/guides/${guideSlug(tool)}/`)
  .filter(url => !existingLocations.has(url))
  .map(url => `  <url><loc>${url}</loc></url>`)
  .join('\n');
if (guideEntries) sitemap = sitemap.replace('</urlset>', `${guideEntries}\n</urlset>`);
fs.writeFileSync(sitemapFile, sitemap);

